using System;

public class Student
{
    public string Name { get; }
    public int Grade { get; }
    public string Subject { get; }

    public Student(string name) : this(name, 9) { }
    public Student(string name, int grade) : this(name, grade, "Math") { }
    public Student(string name, int grade, string subject)
    {
        Name = name;
        Grade = grade;
        Subject = subject;
    }

    public void Display()
    {
        Console.WriteLine($"{Name}, Grade {Grade}, {Subject}");
    }
}

class Program
{
    static void Main()
    {
        var s1 = new Student("Alice");
        var s2 = new Student("Bob", 10, "Science");
        s1.Display();
        s2.Display();
    }
}
